#!/usr/bin/env python3
"""Write full-length articles for all 10 new posts."""
import json
import os

POSTS_FILE = os.path.join(os.path.dirname(__file__), '..', 'data', 'posts.json')

with open(POSTS_FILE) as f:
    posts = json.load(f)

updates = {
    "ahsoka-tano": {
        "content_en": "Ahsoka Tano embodies the evolution of what it means to be a Force user beyond the rigid confines of the Jedi Order. As Anakin Skywalker\u2019s Padawan during the Clone Wars, she demonstrated exceptional skill and independence that often clashed with traditional Jedi doctrine.\n\nHer departure from the Jedi Order marked a pivotal moment in Star Wars lore. Falsely accused of bombing the Jedi Temple, Ahsoka was abandoned by the very institution she served. Though later vindicated, the experience shattered her faith in the Order\u2019s infallibility. Walking down the Temple steps while Anakin watched helplessly remains one of the most devastating scenes in the saga.\n\nAfter surviving Order 66, Ahsoka hid her identity before becoming the covert operative \u201cFulcrum\u201d for the nascent Rebel Alliance. Her white lightsabers, purified from an Inquisitor\u2019s red crystals, symbolized her unique position: wielding the Force without allegiance to either Jedi dogma or Sith corruption.\n\nHer confrontation with Darth Vader on Malachor\u2014facing the man who was once her master and closest friend\u2014is heartbreaking. \u201cI am no Jedi,\u201d she declares, refusing to abandon Anakin even as she fights for her life. That single line encapsulates everything Ahsoka represents: loyalty, independence, and the courage to define your own path.\n\n**Fun Fact:** Ahsoka was originally conceived as a one-off character for the Clone Wars movie. She became so popular that Dave Filoni expanded her story across three animated series and a live-action show, making her one of the most developed characters in the franchise.",
        "content_pl": "Ahsoka Tano uosabia ewolucj\u0119 tego, co znaczy by\u0107 u\u017cytkownikiem Mocy poza sztywnymi ramami Zakonu Jedi. Jako Padawan Anakina Skywalkera podczas Wojen Klon\u00f3w, wykazywa\u0142a wyj\u0105tkowe umiej\u0119tno\u015bci i niezale\u017cno\u015b\u0107, kt\u00f3re cz\u0119sto k\u0142\u00f3ci\u0142y si\u0119 z tradycyjn\u0105 doktryn\u0105 Jedi.\n\nJej odej\u015bcie z Zakonu Jedi by\u0142o prze\u0142omowym momentem sagi. Fa\u0142szywie oskar\u017cona o zamach na \u015awi\u0105tyni\u0119 Jedi, zosta\u0142a porzucona przez instytucj\u0119, kt\u00f3rej s\u0142u\u017cy\u0142a. Cho\u0107 oczyszczona z zarzut\u00f3w, do\u015bwiadczenie to roztrzaska\u0142o jej wiar\u0119 w nieomylno\u015b\u0107 Zakonu. Scena jej odej\u015bcia po stopniach \u015awi\u0105tyni, gdy Anakin patrzy\u0142 bezradnie, pozostaje jedn\u0105 z najbardziej druzgoc\u0105cych w sadze.\n\nPo prze\u017cyciu Rozkazu 66 Ahsoka ukry\u0142a to\u017csamo\u015b\u0107, by sta\u0107 si\u0119 tajn\u0105 agentk\u0105 \u201eFulcrum\u201d dla rodz\u0105cej si\u0119 Rebelii. Jej bia\u0142e miecze \u015bwietlne, oczyszczone z czerwonych kryszta\u0142\u00f3w Inkwizytora, symbolizowa\u0142y jej wyj\u0105tkow\u0105 pozycj\u0119: w\u0142adanie Moc\u0105 bez lojalno\u015bci wobec dogmatu Jedi czy korupcji Sith\u00f3w.\n\nKonfrontacja z Darthem Vaderem na Malachorze\u2014twarz\u0105 w twarz z cz\u0142owiekiem, kt\u00f3ry by\u0142 jej mistrzem i najbli\u017cszym przyjacielem\u2014\u0142amie serce. \u201eNie jestem Jedi\u201d o\u015bwiadcza, odmawiaj\u0105c porzucenia Anakina nawet walcz\u0105c o \u017cycie. To jedno zdanie podsumowuje wszystko, czym jest Ahsoka: lojalno\u015b\u0107, niezale\u017cno\u015b\u0107 i odwag\u0119 definiowania w\u0142asnej \u015bcie\u017cki.\n\n**Ciekawostka:** Ahsoka zosta\u0142a pierwotnie wymy\u015blona jako jednorazowa posta\u0107 do filmu Wojny Klon\u00f3w. Sta\u0142a si\u0119 tak popularna, \u017ce Dave Filoni rozszerzy\u0142 jej histori\u0119 na trzy serie animowane i serial aktorski, czyni\u0105c j\u0105 jedn\u0105 z najbardziej rozwini\u0119tych postaci franczyzy."
    },
    "grand-admiral-thrawn": {
        "content_en": "Grand Admiral Thrawn, born Mitth\u2019raw\u2019nuruodo of the Chiss Ascendancy, stands as the most formidable non-Force sensitive antagonist in Star Wars. In an Empire built on human supremacy, a blue-skinned alien with glowing red eyes rose to the highest military rank through sheer tactical genius.\n\nThrawn\u2019s signature methodology was cultural analysis through art. He studied the paintings, music, architecture, and crafts of a species to understand their psychology, values, and blind spots. This wasn\u2019t mere appreciation\u2014it was weaponized anthropology. By understanding how a people express beauty and meaning, Thrawn predicted how they\u2019d fight, flee, and surrender.\n\nHis campaigns against the Rebel Alliance demonstrated this philosophy ruthlessly. Where other Imperial commanders relied on overwhelming firepower, Thrawn used precise, surgical strikes informed by deep understanding. He turned Phoenix Squadron\u2019s strengths against them, anticipated Hera Syndulla\u2019s tactics, and nearly crushed the Rebellion on Lothal.\n\nWhat makes Thrawn compelling isn\u2019t just his intellect\u2014it\u2019s his courtesy. He\u2019s polite, appreciative of talent, genuinely fascinated by other cultures. He\u2019s a villain you almost want to succeed, which makes him far more dangerous than any screaming Imperial officer.\n\n**Fun Fact:** Thrawn was created by author Timothy Zahn in 1991 for \u2018Heir to the Empire,\u2019 the novel that revived Star Wars fiction and essentially created the Expanded Universe. His original Legends trilogy sold over 15 million copies.",
        "content_pl": "Wielki Admira\u0142 Thrawn, urodzony jako Mitth\u2019raw\u2019nuruodo z Dominium Chiss\u00f3w, jest najbardziej gro\u017anym antagonist\u0105 niepos\u0142uguj\u0105cym si\u0119 Moc\u0105 w Star Wars. W Imperium zbudowanym na ludzkiej supremacji, niebiesksk\u00f3ry obcy z p\u0142on\u0105cymi czerwonymi oczami wzni\u00f3s\u0142 si\u0119 na najwy\u017csz\u0105 rang\u0119 wojskow\u0105 dzi\u0119ki samemu geniuszowi taktycznemu.\n\nMetoda Thrawna to analiza kulturowa przez sztuk\u0119. Studiowa\u0142 malarstwo, muzyk\u0119, architektur\u0119 i rzemios\u0142o gatunku, by zrozumie\u0107 psychologi\u0119, warto\u015bci i s\u0142abe punkty. To nie by\u0142o zwyk\u0142e podziwianie\u2014to uzbrojona antropologia. Rozumiej\u0105c, jak lud wyra\u017ca pi\u0119kno i sens, Thrawn przewidywa\u0142, jak b\u0119d\u0105 walczy\u0107, ucieka\u0107 i kapitulowa\u0107.\n\nJego kampanie przeciwko Rebelii demonstrowa\u0142y t\u0119 filozofi\u0119 bezlito\u015bnie. Gdzie inni imperialni dow\u00f3dcy polegali na przygniataj\u0105cej sile ognia, Thrawn stosowa\u0142 precyzyjne, chirurgiczne uderzenia oparte na g\u0142\u0119bokim zrozumieniu. Obr\u00f3ci\u0142 mocne strony Eskadry Phoenix przeciw nim, przewidzia\u0142 taktyk\u0119 Hery Syndulli i niemal zmiażd\u017cy\u0142 Rebeli\u0119 na Lothalu.\n\nTo, co czyni Thrawna fascynuj\u0105cym, to nie tylko intelekt\u2014to jego uprzejmo\u015b\u0107. Jest grzeczny, docenia talent, szczerze zafascynowany innymi kulturami. To z\u0142oczy\u0144ca, kt\u00f3remu prawie chcesz kibicowa\u0107, co czyni go znacznie niebezpieczniejszym ni\u017c jakikolwiek krzyczy\u0105cy oficer imperialny.\n\n**Ciekawostka:** Thrawn zosta\u0142 stworzony przez Timothy\u2019ego Zahna w 1991 roku dla powie\u015bci \u201eSpadkobierca Imperium,\u201d kt\u00f3ra o\u017cywi\u0142a fikcj\u0119 Star Wars i stworzy\u0142a Expanded Universe. Jego oryginalna trylogia Legends sprzeda\u0142a si\u0119 w ponad 15 milionach egzemplarzy."
    },
    "order-66": {
        "content_en": "Order 66 was the most devastating betrayal in galactic history. With three words\u2014\u201cExecute Order 66\u201d\u2014Chancellor Palpatine activated a contingency protocol hidden in the biochips of every clone trooper, compelling them to kill their Jedi commanders without hesitation or mercy.\n\nThe horror wasn\u2019t just in the killing. It was in the intimacy of the betrayal. Jedi and clones had fought side by side for three years of brutal warfare. They had saved each other\u2019s lives, shared meals, mourned fallen comrades. Commander Cody, who had served loyally with Obi-Wan Kenobi through countless campaigns, tried to blast him off a cliff without a moment\u2019s pause.\n\nAcross the galaxy, the purge unfolded simultaneously. Ki-Adi-Mundi fell on Mygeeto, cut down by the troopers he was leading into battle. Aayla Secura was shot in the back on Felucia. Young Padawans in the Jedi Temple were slaughtered by Darth Vader himself\u2014a man they had known as Anakin Skywalker, hero of the Republic.\n\nThe cruelty of Order 66\u2019s design was its perfection. The biochips removed choice from the clones\u2014most would have refused otherwise. Some, like Captain Rex, resisted long enough for the chip to be removed, tears streaming down his face as he gasped \u201cFind him\u2014find Fives.\u201d But they were the rare exceptions.\n\n**Fun Fact:** The inhibitor chip concept was added by The Clone Wars series. In the original films, the implication was that clones simply followed orders\u2014the series added devastating moral complexity by showing it was never their choice.",
        "content_pl": "Rozkaz 66 by\u0142 najbardziej druzgoc\u0105c\u0105 zdrad\u0105 w galaktycznej historii. Trzema s\u0142owami\u2014\u201eWykona\u0107 Rozkaz 66\u201d\u2014Kanclerz Palpatine aktywowa\u0142 protok\u00f3\u0142 ukryty w biochipach ka\u017cdego \u017co\u0142nierza klona, zmuszaj\u0105c ich do zabicia dow\u00f3dc\u00f3w Jedi bez wahania czy lito\u015bci.\n\nGroza nie tkwi\u0142a tylko w zabijaniu. Tkwi\u0142a w intymno\u015bci zdrady. Jedi i klony walczyli rami\u0119 w rami\u0119 przez trzy lata brutalnej wojny. Ratowali sobie nawzajem \u017cycie, dzielili posi\u0142ki, op\u0142akiwali poleg\u0142ych towarzyszy. Dow\u00f3dca Cody, kt\u00f3ry s\u0142u\u017cy\u0142 lojalnie z Obi-Wanem Kenobim, pr\u00f3bowa\u0142 go zestrzeli\u0107 z klifu bez chwili wahania.\n\nW ca\u0142ej galaktyce czystka rozwija\u0142a si\u0119 jednocze\u015bnie. Ki-Adi-Mundi pad\u0142 na Mygeeto, \u015bci\u0119ty przez \u017co\u0142nierzy, kt\u00f3rych prowadzi\u0142 do bitwy. Aayla Secura zosta\u0142a zastrzelona w plecy na Felucii. M\u0142odzi Padawani w \u015awi\u0105tyni Jedi zostali wymordowani przez samego Dartha Vadera\u2014cz\u0142owieka, kt\u00f3rego znali jako Anakina Skywalkera, bohatera Republiki.\n\nOkrucie\u0144stwo konstrukcji Rozkazu 66 tkwi\u0142o w jego doskona\u0142o\u015bci. Biochipy odebra\u0142y klonom wyb\u00f3r\u2014wi\u0119kszo\u015b\u0107 odm\u00f3wi\u0142aby. Niekt\u00f3rzy, jak Kapitan Rex, oparli si\u0119 wystarczaj\u0105co d\u0142ugo, by chip zosta\u0142 usuni\u0119ty, ze \u0142zami p\u0142yn\u0105cymi po twarzy, dysz\u0105c \u201eZnajd\u017a go\u2014znajd\u017a Fivesa.\u201d Ale byli rzadkimi wyj\u0105tkami.\n\n**Ciekawostka:** Koncepcja chip\u00f3w hamuj\u0105cych zosta\u0142a dodana przez serial Wojny Klon\u00f3w. W oryginalnych filmach sugerowano, \u017ce klony po prostu wykonywa\u0142y rozkazy\u2014serial doda\u0142 druzgoc\u0105c\u0105 moraln\u0105 z\u0142o\u017cono\u015b\u0107, pokazuj\u0105c, \u017ce to nigdy nie by\u0142 ich wyb\u00f3r."
    },
    "ebon-hawk": {
        "content_en": "The Ebon Hawk is the Millennium Falcon\u2019s spiritual ancestor\u2014a nimble, heavily modified freighter that carried some of the Old Republic\u2019s most important figures across the galaxy during its darkest hours. Like its successor thousands of years later, the Hawk was fast, tough, and perpetually in need of repair.\n\nOriginally a smuggling vessel, the Ebon Hawk passed through numerous owners before becoming intertwined with the fate of Revan. During the Jedi Civil War, the ship served as base of operations for Revan\u2019s crew as they searched for the Star Maps leading to the Star Forge.\n\nThe Hawk\u2019s design reflects an era of rougher, more industrial starship construction. Lacking the Falcon\u2019s smooth curves, the Ebon Hawk has an angular, utilitarian appearance\u2014a ship built for function over form. Her cargo holds had been converted into hidden compartments, engines modified for speed, weapons upgraded for combat.\n\nWhat makes the Ebon Hawk truly special isn\u2019t her specifications\u2014it\u2019s the conversations that happened aboard her. The ship\u2019s main hold became a gathering point for one of the most diverse and conflicted crews in Star Wars history: Jedi, Sith, soldiers, droids, and Mandalorians debating philosophy, purpose, and the nature of the Force. Kreia\u2019s lectures on the failures of both Jedi and Sith, delivered in the ship\u2019s dim corridors, remain some of the deepest philosophical writing in the franchise.\n\n**Fun Fact:** The Ebon Hawk was deliberately designed to evoke the Millennium Falcon in Knights of the Old Republic, giving players that same sense of \u2018home base\u2019 that Han Solo\u2019s ship provided in the films. The name itself suggests darkness and speed\u2014a perfect fit for a ship that served both light and dark.",
        "content_pl": "Ebon Hawk to duchowy przodek Soko\u0142a Millennium\u2014zwinny, mocno zmodyfikowany frachtowiec, kt\u00f3ry wi\u00f3z\u0142 jedne z najwa\u017cniejszych postaci Starej Republiki przez galaktyk\u0119 w jej najciemniejszych godzinach. Podobnie jak jego nast\u0119pca tysi\u0105ce lat p\u00f3\u017aniej, Hawk by\u0142 szybki, wytrzyma\u0142y i nieustannie potrzebuj\u0105cy naprawy.\n\nPocz\u0105tkowo statek przemytniczy, Ebon Hawk przeszed\u0142 przez r\u0119ce licznych w\u0142a\u015bcicieli, zanim los spl\u00f3t\u0142 go z Revanem. Podczas Jedia\u0144skiej Wojny Domowej s\u0142u\u017cy\u0142 jako baza operacyjna za\u0142ogi Revana poszukuj\u0105cej Map Gwiezdnych prowadz\u0105cych do Gwiezdnej Ku\u017ani.\n\nDesign Hawka odzwierciedla er\u0119 bardziej surowej, industrialnej konstrukcji statk\u00f3w. Pozbawiony g\u0142adkich krzywych Falcona, Ebon Hawk ma kanciasty, utylitarny wygl\u0105d\u2014statek zbudowany dla funkcji, nie formy. \u0141adownie przerobione na ukryte schowki, silniki zmodyfikowane pod pr\u0119dko\u015b\u0107, bro\u0144 ulepszona do walki.\n\nTo, co czyni Ebon Hawka naprawd\u0119 wyj\u0105tkowym, to nie specyfikacja\u2014to rozmowy na jego pok\u0142adzie. G\u0142\u00f3wna \u0142adownia sta\u0142a si\u0119 miejscem spotka\u0144 jednej z najbardziej zr\u00f3\u017cnicowanych za\u0142\u00f3g w historii Star Wars: Jedi, Sithowie, \u017co\u0142nierze, droidy i Mandalorianie debatuj\u0105cy o filozofii, celu i naturze Mocy. Wyk\u0142ady Krei o pora\u017ckach zar\u00f3wno Jedi, jak i Sith\u00f3w, wyg\u0142aszane w ciemnych korytarzach statku, pozostaj\u0105 jednym z najg\u0142\u0119bszych filozoficznych tekst\u00f3w franczyzy.\n\n**Ciekawostka:** Ebon Hawk zosta\u0142 celowo zaprojektowany, by przypomina\u0107 Soko\u0142a Millennium w KOTOR, daj\u0105c graczom to samo poczucie \u201ebazy\u201d. Sama nazwa sugeruje ciemno\u015b\u0107 i pr\u0119dko\u015b\u0107\u2014idealne po\u0142\u0105czenie dla statku, kt\u00f3ry s\u0142u\u017cy\u0142 zar\u00f3wno \u015bwiat\u0142u, jak i ciemno\u015bci."
    },
    "siege-of-mandalore": {
        "content_en": "The Siege of Mandalore is the Clone Wars\u2019 masterpiece finale\u2014a battle that unfolds simultaneously with Revenge of the Sith, lending devastating context to both stories. While Anakin Skywalker falls to the dark side on Coruscant, Ahsoka Tano fights for survival on Mandalore.\n\nAhsoka leads a division of the 501st Legion\u2014clone troopers who painted their helmets orange in her honor\u2014against Darth Maul\u2019s Shadow Collective. The battle begins as a conventional siege but escalates into something far more personal when Ahsoka confronts Maul in the throne room of Sundari.\n\nTheir duel is not just combat\u2014it\u2019s a clash of two people who both sense the coming catastrophe. Maul knows Sidious\u2019s plan and desperately tries to convince Ahsoka to join him in stopping it. When she refuses, their fight becomes a masterwork of choreography and emotion, ending with Ahsoka using the Force to capture Maul in a collapsing beam structure.\n\nThen Order 66 strikes. The final episodes depict Ahsoka and Captain Rex fighting to survive against their own men\u2014clones they led and loved, now mindlessly trying to kill them. Rex\u2019s chip-removal scene, where he resists the programming with tears streaming down his face, gasping \u201cFind him\u2014find Fives,\u201d is perhaps the most emotionally raw moment in all of Star Wars animation.\n\nThe series ends with Ahsoka standing alone in the snow, surrounded by clone trooper graves she dug herself. Her lightsaber, abandoned. The Republic, dead.\n\n**Fun Fact:** The final arc was animated in a cinematic style with a wider aspect ratio, making it visually distinct from the rest of the series\u2014Dave Filoni wanted it to feel like a Star Wars film.",
        "content_pl": "Obl\u0119\u017cenie Mandalore to arcydzie\u0142ne zako\u0144czenie Wojen Klon\u00f3w\u2014bitwa rozgrywaj\u0105ca si\u0119 jednocze\u015bnie z Zemst\u0105 Sith\u00f3w, nadaj\u0105ca obu historiom druzgoc\u0105cy kontekst. Gdy Anakin Skywalker upada na ciemn\u0105 stron\u0119 na Coruscant, Ahsoka Tano walczy o przetrwanie na Mandalore.\n\nAhsoka prowadzi dywizj\u0119 501. Legionu\u2014\u017co\u0142nierzy klon\u00f3w, kt\u00f3rzy pomalowali he\u0142my na pomara\u0144czowo na jej cze\u015b\u0107\u2014przeciwko Zbiorowemu Cieniowi Dartha Maula. Bitwa zaczyna si\u0119 konwencjonalnie, ale eskaluje, gdy Ahsoka staje naprzeciw Maula w sali tronowej Sundari.\n\nIch pojedynek to nie tylko walka\u2014to starcie dw\u00f3ch os\u00f3b, kt\u00f3re obie wyczuwaj\u0105 nadchodz\u0105c\u0105 katastrof\u0119. Maul zna plan Sidiousa i desperacko pr\u00f3buje przekona\u0107 Ahsok\u0119. Gdy odmawia, ich walka staje si\u0119 mistrzowskim dzie\u0142em choreografii i emocji, ko\u0144cz\u0105c si\u0119 schwytaniem Maula przy u\u017cyciu Mocy.\n\nWtedy uderza Rozkaz 66. Ostatnie odcinki przedstawiaj\u0105 Ahsok\u0119 i Kapitana Rexa walcz\u0105cych o przetrwanie przeciwko w\u0142asnym ludziom\u2014klonom, kt\u00f3rymi dowodzili i kt\u00f3rych kochali. Scena usuni\u0119cia chipu Rexa, gdzie opiera si\u0119 programowaniu ze \u0142zami, dysz\u0105c \u201eZnajd\u017a go\u2014znajd\u017a Fivesa,\u201d jest najbardziej emocjonalnym momentem animacji Star Wars.\n\nSerial ko\u0144czy si\u0119 Ahsok\u0105 stoj\u0105c\u0105 samotnie w \u015bniegu, otoczon\u0105 grobami klon\u00f3w, kt\u00f3re sama wykopa\u0142a. Miecz \u015bwietlny, porzucony. Republika, martwa.\n\n**Ciekawostka:** Ostatni \u0142uk fabularny animowano w stylu kinowym z szerszym formatem obrazu\u2014Dave Filoni chcia\u0142, by wygl\u0105da\u0142 jak film Star Wars."
    },
    "darth-nihilus": {
        "content_en": "Darth Nihilus is perhaps the most terrifying Sith Lord in Star Wars lore\u2014not because of his power or ambition, but because of what he had become. He was no longer truly a person. He was hunger incarnate, a wound in the Force that consumed all life around him to sustain its own existence.\n\nNihilus was a survivor of the Mandalorian Wars, specifically the activation of the Mass Shadow Generator at Malachor V\u2014a superweapon that killed thousands of Mandalorians and Republic soldiers simultaneously. The trauma of that event, combined with exposure to the resulting wound in the Force, transformed Nihilus into something unprecedented.\n\nHe developed the ability to drain the Force from living beings on a planetary scale. His consumption of Katarr\u2014a Miraluka colony world\u2014killed every living thing on the planet in an instant. Only Visas Marr survived, drawn to him by a connection she couldn\u2019t understand, becoming his apprentice and translator.\n\nWhat makes Nihilus uniquely horrifying is that his power was also his prison. He couldn\u2019t stop consuming. His hunger grew with every world he drained, and his physical form deteriorated until he was nothing more than dark side energy held together by his robes and mask. His voice became unintelligible\u2014a distorted, ancient language that only Visas could interpret.\n\n**Fun Fact:** Nihilus\u2019s mask became one of the most iconic Sith designs in Star Wars. Its stark white-and-red pattern against his shadowy form influenced countless fan art interpretations and became a symbol of \u2018faceless evil\u2019 throughout the franchise.",
        "content_pl": "Darth Nihilus jest by\u0107 mo\u017ce najbardziej przera\u017caj\u0105cym Lordem Sith\u00f3w w Star Wars\u2014nie z powodu mocy czy ambicji, ale z powodu tego, czym si\u0119 sta\u0142. Nie by\u0142 ju\u017c naprawd\u0119 osob\u0105. By\u0142 g\u0142odem wcielonym, ran\u0105 w Mocy poch\u0142aniaj\u0105c\u0105 wszelkie \u017cycie woko\u0142 siebie, by podtrzyma\u0107 w\u0142asn\u0105 egzystencj\u0119.\n\nNihilus by\u0142 ocalonym z Wojen Mandloria\u0144skich, konkretnie aktywacji Generatora Cienia Masowego na Malachorze V\u2014superbroni, kt\u00f3ra zabi\u0142a jednocze\u015bnie tysi\u0105ce Mandalorian i \u017co\u0142nierzy Republiki. Trauma tego wydarzenia, po\u0142\u0105czona z ekspozycj\u0105 na ran\u0119 w Mocy, przekszta\u0142ci\u0142a Nihilusa w co\u015b bezprecedensowego.\n\nRozwin\u0105\u0142 zdolno\u015b\u0107 wysysania Mocy z \u017cywych istot na planetarn\u0105 skal\u0119. Poch\u0142oni\u0119cie Katarr\u2014\u015bwiata-kolonii Miraluk\u00f3w\u2014zabi\u0142o ka\u017cd\u0105 \u017cyw\u0105 istot\u0119 w mgnieniu oka. Tylko Visas Marr prze\u017cy\u0142a, przyci\u0105gni\u0119ta po\u0142\u0105czeniem, kt\u00f3rego nie rozumia\u0142a, staj\u0105c si\u0119 jego uczennic\u0105 i t\u0142umaczk\u0105.\n\nTo, co czyni Nihilusa wyj\u0105tkowo przera\u017caj\u0105cym: jego moc by\u0142a te\u017c wi\u0119zieniem. Nie m\u00f3g\u0142 przesta\u0107 poch\u0142ania\u0107. G\u0142\u00f3d r\u00f3s\u0142 z ka\u017cdym wyssanym \u015bwiatem, a fizyczna forma degradowa\u0142a si\u0119, a\u017c zosta\u0142 niczym wi\u0119cej ni\u017c energi\u0105 ciemnej strony utrzymywan\u0105 przez szaty i mask\u0119. G\u0142os sta\u0142 si\u0119 niezrozumia\u0142y\u2014zniekszta\u0142cony, staro\u017cytny j\u0119zyk, kt\u00f3ry tylko Visas mog\u0142a interpretowa\u0107.\n\n**Ciekawostka:** Maska Nihilusa sta\u0142a si\u0119 jednym z najbardziej ikonicznych design\u00f3w Sith\u00f3w. Jej kontrastowy bia\u0142o-czerwony wz\u00f3r na tle mrocznej sylwetki zainspirowa\u0142 niezliczony fan art i sta\u0142 si\u0119 symbolem \u201ebeztwarzowego z\u0142a\u201d w ca\u0142ej franczyzie."
    },
    "world-between-worlds": {
        "content_en": "The World Between Worlds is one of the most profound concepts ever introduced to Star Wars canon. Discovered by Ezra Bridger beneath the Jedi Temple on Lothal, this mystical dimension exists outside normal space-time, connecting moments across history through doorways illuminated by starlight.\n\nThe World manifests as an endless void filled with interconnected pathways and portals. Through these portals, one can observe\u2014and potentially alter\u2014events from any point in time. Voices of Jedi past and future echo through the space: Yoda, Obi-Wan, Qui-Gon, Ahsoka, even Rey and Kylo Ren from decades in the future.\n\nEzra used the World Between Worlds to save Ahsoka Tano from death at the hands of Darth Vader on Malachor. By reaching through a portal into the past, he pulled her out of the collapsing Sith temple moments before Vader\u2019s killing blow\u2014proving that the World can indeed change the timeline.\n\nEmperor Palpatine desperately sought access to the World, understanding that control over time itself would make him truly omnipotent. The fact that a Jedi Temple guarded its entrance suggests the Force itself placed safeguards against such abuse. Ezra ultimately sealed the Lothal portal, understanding that some powers must remain beyond anyone\u2019s reach.\n\n**Fun Fact:** The concept was inspired by Dave Filoni\u2019s conversations with George Lucas about the nature of the Force, and draws on Joseph Campbell\u2019s mythological concept of the \u2018axis mundi\u2019\u2014the cosmic center connecting heaven and earth.",
        "content_pl": "\u015awiat Mi\u0119dzy \u015awiatami to jedna z najg\u0142\u0119bszych koncepcji wprowadzonych do kanonu Star Wars. Odkryty przez Ezr\u0119 Bridgera pod \u015awi\u0105tyni\u0105 Jedi na Lothalu, ten mistyczny wymiar istnieje poza normaln\u0105 czasoprzestrzeni\u0105, \u0142\u0105cz\u0105c momenty w historii przez bramy o\u015bwietlone gwiazdami.\n\n\u015awiat manifestuje si\u0119 jako niesko\u0144czona pustka wype\u0142niona po\u0142\u0105czonymi \u015bcie\u017ckami i portalami. Przez te portale mo\u017cna obserwowa\u0107\u2014i potencjalnie zmienia\u0107\u2014wydarzenia z ka\u017cdego punktu w czasie. G\u0142osy Jedi z przesz\u0142o\u015bci i przysz\u0142o\u015bci odbijaj\u0105 si\u0119 echem: Yoda, Obi-Wan, Qui-Gon, Ahsoka, nawet Rey i Kylo Ren z odleg\u0142ej przysz\u0142o\u015bci.\n\nEzra u\u017cy\u0142 \u015awiata Mi\u0119dzy \u015awiatami, by uratowa\u0107 Ahsok\u0119 Tano od \u015bmierci z r\u0105k Dartha Vadera na Malachorze. Si\u0119gaj\u0105c przez portal w przesz\u0142o\u015b\u0107, wyci\u0105gn\u0105\u0142 j\u0105 z rozpadaj\u0105cej si\u0119 \u015bwi\u0105tyni Sith\u00f3w\u2014dowodz\u0105c, \u017ce \u015awiat rzeczywi\u015bcie mo\u017ce zmienia\u0107 o\u015b czasu.\n\nCesarz Palpatine desperacko szuka\u0142 dost\u0119pu, rozumiej\u0105c, \u017ce kontrola nad samym czasem uczyni\u0142aby go wszechmocnym. Fakt, \u017ce \u015awi\u0105tynia Jedi strze\u017ce wej\u015bcia, sugeruje, \u017ce Moc umie\u015bci\u0142a zabezpieczenia. Ezra ostatecznie zapieczętowa\u0142 portal na Lothalu, rozumiej\u0105c, \u017ce niekt\u00f3re moce musz\u0105 pozosta\u0107 poza czyimkolwiek zasi\u0119giem.\n\n**Ciekawostka:** Koncepcja zainspirowana rozmowami Dave\u2019a Filoniego z George\u2019em Lucasem o naturze Mocy. Czerpie z mitologicznej koncepcji Josepha Campbella \u201eaxis mundi\u201d\u2014kosmicznego centrum \u0142\u0105cz\u0105cego niebo i ziemi\u0119."
    },
    "korriban-moraband": {
        "content_en": "Korriban\u2014later known as Moraband\u2014is the spiritual heart of the Sith Order. This desolate, red-sanded world in the Outer Rim was the homeworld of the Sith species, and for millennia served as the seat of Sith power, learning, and burial.\n\nThe Valley of the Dark Lords dominates the landscape: a massive canyon lined with enormous stone tombs of ancient Sith Lords. Each tomb is a monument to power and a repository of dark side knowledge, protected by traps, spirits, and dark side energy so concentrated it drives the unprepared insane.\n\nThe Sith Academy on Korriban trained generations of dark side acolytes. Aspiring Sith were sent into the tombs to prove their worth\u2014retrieving artifacts, surviving dark side spirits, and demonstrating the ruthlessness required to wield power. Many entered. Few emerged.\n\nThe planet\u2019s connection to the dark side is so strong that it warps reality itself. Visitors experience visions, hear voices of dead Sith, and feel the crushing weight of accumulated centuries of hatred and ambition. Even Yoda, when he visited Moraband during the Clone Wars, faced terrifying illusions conjured by the dark side\u2014including a vision of Darth Bane that tested his resolve.\n\n**Fun Fact:** The planet was called \u2018Korriban\u2019 in Legends material including KOTOR, but George Lucas renamed it \u2018Moraband\u2019 for The Clone Wars. Both names are now considered canon, with Moraband being the more contemporary designation.",
        "content_pl": "Korriban\u2014p\u00f3\u017aniej znany jako Moraband\u2014to duchowe serce Zakonu Sith\u00f3w. Ten pustynny, czerwonopiastkowy \u015bwiat na Zewn\u0119trznym Kraw\u0119dzi by\u0142 ojczyzn\u0105 gatunku Sith\u00f3w i przez tysi\u0105clecia siedzib\u0105 sitha\u0144skiej w\u0142adzy, nauki i poch\u00f3wku.\n\nDolina Mrocznych Lord\u00f3w dominuje krajobraz: masywny kanion wy\u0142o\u017cony ogromnymi kamiennymi grobowcami staro\u017cytnych Lord\u00f3w Sith\u00f3w. Ka\u017cdy grobowiec jest monumentem mocy i skarbnic\u0105 wiedzy ciemnej strony, chronionym pu\u0142apkami, duchami i energi\u0105 ciemnej strony tak skoncentrowan\u0105, \u017ce doprowadza nieprzygotowanych do szale\u0144stwa.\n\nAkademia Sith\u00f3w na Korribanie szkoli\u0142a pokolenia adept\u00f3w ciemnej strony. Aspiruj\u0105cy Sithowie byli wysy\u0142ani do grobovc\u00f3w, by udowodni\u0107 warto\u015b\u0107\u2014odzyskuj\u0105c artefakty, prze\u017cywaj\u0105c duchy i demonstruj\u0105c bezwzgl\u0119dno\u015b\u0107 wymagan\u0105 do w\u0142adania moc\u0105. Wielu wchodzi\u0142o. Niewielu wychodzi\u0142o.\n\nPo\u0142\u0105czenie planety z ciemn\u0105 stron\u0105 jest tak silne, \u017ce zakrzywia sam\u0105 rzeczywisto\u015b\u0107. Odwiedzaj\u0105cy do\u015bwiadczaj\u0105 wizji, s\u0142ysz\u0105 g\u0142osy martwych Sith\u00f3w i czuj\u0105 mia\u017cd\u017c\u0105cy ci\u0119\u017car wiek\u00f3w nienawi\u015bci. Nawet Yoda, gdy odwiedzi\u0142 Moraband podczas Wojen Klon\u00f3w, stan\u0105\u0142 przed przera\u017caj\u0105cymi iluzjami\u2014w tym wizj\u0105 Dartha Bane\u2019a testuj\u0105c\u0105 jego determinacj\u0119.\n\n**Ciekawostka:** Planeta nosi\u0142a nazw\u0119 \u201eKorriban\u201d w materia\u0142ach Legends (w\u0142\u0105cznie z KOTOR), ale George Lucas przemianowa\u0142 j\u0105 na \u201eMoreband\u201d dla Wojen Klon\u00f3w. Obie nazwy s\u0105 teraz kanonem."
    },
    "star-forge": {
        "content_en": "The Star Forge was the ultimate weapon of the ancient Rakatan Infinite Empire\u2014a colossal space station that drew power from a nearby star and the dark side of the Force to manufacture an endless supply of warships, battle droids, and war material. It was the pinnacle of dark side technology, and perhaps the most dangerous artifact ever created.\n\nBuilt over 25,000 years before the Battle of Yavin, the Star Forge was the engine behind the Rakatans\u2019 galactic conquest. It didn\u2019t just build ships\u2014it fed on the dark side energy of its operators, amplifying their aggression and corruption while growing more powerful. The station was essentially alive, a dark side nexus that consumed its users even as it served them.\n\nWhen the Rakatan Infinite Empire collapsed\u2014destroyed by a plague that severed their connection to the Force\u2014the Star Forge was lost. It orbited a forgotten star in an uncharted system, protected by a disruptor field that scrambled navigation computers, waiting to be found again.\n\nRevan rediscovered the Star Forge after following a trail of Star Maps scattered across the galaxy. As a Sith Lord, he used it to build a massive fleet that nearly conquered the Republic. Later, redeemed and memory-wiped, Revan returned to destroy the station he had once wielded, understanding that the Star Forge would corrupt anyone who used it.\n\n**Fun Fact:** The Star Forge\u2019s design was partially inspired by a Dyson sphere\u2014a theoretical megastructure that completely encompasses a star to harvest its energy output. The game developers wanted it to feel truly alien and impossibly ancient.",
        "content_pl": "Gwiezdna Ku\u017ania by\u0142a ostateczn\u0105 broni\u0105 staro\u017cytnego Niesko\u0144czonego Imperium Rakatan\u00f3w\u2014kolosaln\u0105 stacj\u0105 kosmiczn\u0105 czerpi\u0105c\u0105 moc z pobliskiej gwiazdy i ciemnej strony Mocy do wytwarzania niesko\u0144czonych zapas\u00f3w okr\u0119t\u00f3w wojennych, droid\u00f3w bojowych i materia\u0142\u00f3w. Szczyt technologii ciemnej strony i by\u0107 mo\u017ce najniebezpieczniejszy artefakt w historii.\n\nZbudowana ponad 25 000 lat przed Bitw\u0105 o Yavin, Ku\u017ania by\u0142a silnikiem rakata\u0144skiego podboju galaktyki. Nie tylko budowa\u0142a statki\u2014karmi\u0142a si\u0119 energi\u0105 ciemnej strony operator\u00f3w, wzmacniaj\u0105c ich agresj\u0119 i korupcj\u0119, jednocze\u015bnie staj\u0105c si\u0119 pot\u0119\u017cniejsza. Stacja by\u0142a w zasadzie \u017cywa, nexusem ciemnej strony poch\u0142aniaj\u0105cym u\u017cytkownik\u00f3w nawet im s\u0142u\u017c\u0105c.\n\nGdy Niesko\u0144czone Imperium upad\u0142o\u2014zniszczone przez plag\u0119 odcinaj\u0105c\u0105 Rakatan\u00f3w od Mocy\u2014Ku\u017ania zosta\u0142a utracona. Orbitowa\u0142a wok\u00f3\u0142 zapomnianej gwiazdy, chroniona polem zak\u0142\u00f3caj\u0105cym komputery nawigacyjne.\n\nRevan odkry\u0142 Ku\u017ani\u0119 \u015bledz\u0105c szlak Map Gwiezdnych. Jako Lord Sith\u00f3w zbudowa\u0142 masow\u0105 flot\u0119 gro\u017c\u0105c\u0105 Republice. P\u00f3\u017aniej, odkupiony i z wymazan\u0105 pami\u0119ci\u0105, wr\u00f3ci\u0142, by zniszczy\u0107 stacj\u0119, rozumiej\u0105c, \u017ce Ku\u017ania skorumpuje ka\u017cdego.\n\n**Ciekawostka:** Design Ku\u017ani zosta\u0142 cz\u0119\u015bciowo zainspirowany sfer\u0105 Dysona\u2014teoretyczn\u0105 megastruktur\u0105 ca\u0142kowicie otaczaj\u0105c\u0105 gwiazd\u0119 w celu pozyskania energii. Tw\u00f3rcy gry chcieli, by wygl\u0105da\u0142a naprawd\u0119 obco i niemo\u017cliwie staro\u017cytnie."
    },
    "battle-of-malachor": {
        "content_en": "The Battle of Malachor is one of the most catastrophic events in galactic history\u2014a conflict so devastating that it scarred both the planet and the Force itself. Two versions of this battle exist in Star Wars lore, both carrying immense weight.\n\nIn the ancient past, a massive battle between the Jedi and the Sith took place on Malachor. A superweapon within the Sith temple was activated during the fighting, instantly petrifying every combatant on the battlefield. Thousands of years later, when Ahsoka Tano, Kanan Jarrus, and Ezra Bridger explored the planet, they found the battlefield exactly as it was frozen\u2014Jedi and Sith locked in combat for eternity, lightsabers still clutched in stone hands.\n\nDuring the Mandalorian Wars, Malachor V became the site of another apocalyptic battle. The Jedi General known as the Exile activated the Mass Shadow Generator, a gravity-based superweapon that crushed both the Mandalorian fleet and a significant portion of the Republic\u2019s own forces. The screams of thousands dying simultaneously through the Force created a wound so deep it would produce Darth Nihilus.\n\nMalachor represents the ultimate consequence of unchecked warfare. Both battles demonstrate that pursuing victory at any cost\u2014whether through Sith superweapons or Republic desperation\u2014leads to devastation echoing through millennia.\n\n**Fun Fact:** The petrified battlefield scene in Rebels was inspired by the ruins of Pompeii, where volcanic ash preserved the final moments of an ancient civilization\u2014Dave Filoni wanted viewers to feel the same eerie sense of frozen time.",
        "content_pl": "Bitwa o Malachor to jedno z najbardziej katastroficznych wydarze\u0144 w galaktycznej historii\u2014konflikt tak druzgoc\u0105cy, \u017ce zostawi\u0142 blizn\u0119 zar\u00f3wno na planecie, jak i na samej Mocy. Dwie wersje tej bitwy istniej\u0105 w Star Wars, obie nios\u0105c ogromny ci\u0119\u017car.\n\nW staro\u017cytnej przesz\u0142o\u015bci masowa bitwa mi\u0119dzy Jedi a Sithami mia\u0142a miejsce na Malachorze. Superbro\u0144 wewn\u0105trz \u015bwi\u0105tyni Sith\u00f3w zosta\u0142a aktywowana podczas walki, natychmiast petryfikuj\u0105c ka\u017cdego kombatanta. Tysi\u0105ce lat p\u00f3\u017aniej Ahsoka, Kanan i Ezra znale\u017ali pole bitwy dok\u0142adnie takie, jakim zosta\u0142o zamro\u017cone\u2014Jedi i Sithowie zamkni\u0119ci w walce na wieczno\u015b\u0107, miecze \u015bwietlne wci\u0105\u017c zaci\u015bni\u0119te w kamiennych d\u0142oniach.\n\nPodczas Wojen Mandloria\u0144skich Malachor V sta\u0142 si\u0119 miejscem kolejnej apokaliptycznej bitwy. Genera\u0142 Jedi znany jako Wygnaniec aktywowa\u0142 Generator Cienia Masowego, superbro\u0144 grawitacyjn\u0105, kt\u00f3ra zmia\u017cd\u017cy\u0142a zar\u00f3wno flot\u0119 Mandalorian, jak i znaczn\u0105 cz\u0119\u015b\u0107 si\u0142 Republiki. Krzyki tysi\u0119cy umieraj\u0105cych jednocze\u015bnie przez Moc stworzy\u0142y ran\u0119 tak g\u0142\u0119bok\u0105, \u017ce zrodzi\u0142a Dartha Nihilusa.\n\nMalachor reprezentuje ostateczn\u0105 konsekwencj\u0119 niekontrolowanej wojny. Obie bitwy pokazuj\u0105, \u017ce d\u0105\u017cenie do zwyci\u0119stwa za wszelk\u0105 cen\u0119 prowadzi do dewastacji odbijaj\u0105cej si\u0119 echem przez tysi\u0105clecia.\n\n**Ciekawostka:** Scena skamienia\u0142ego pola bitwy w Rebels zainspirowana ruinami Pompej\u00f3w\u2014Filoni chcia\u0142, by widzowie poczuli ten sam niesamowity sens zamro\u017conego czasu."
    }
}

for slug, content in updates.items():
    for p in posts:
        if p['slug'] == slug:
            p['content_en'] = content['content_en']
            p['content_pl'] = content['content_pl']
            en_len = len(content['content_en'])
            pl_len = len(content['content_pl'])
            print(f"Updated {slug:30s} EN:{en_len:5d} PL:{pl_len:5d}")
            break

# Also ensure all posts have image_url
for p in posts:
    if not p.get('image_url'):
        p['image_url'] = f"/images/posts/{p['slug']}.webp"

with open(POSTS_FILE, 'w') as f:
    json.dump(posts, f, indent=2, ensure_ascii=False)

print(f"\nDone. Total posts: {len(posts)}")
